export const API_BASE_URL = "/api/fitness";

/**
 * Нормализует базовый URL API.
 */
const normalizeBaseUrl = (base: string) => {
  const trimmed = base.trim();
  if (!trimmed) return "https://wedev-api.sky.pro";
  if (trimmed.startsWith("http://") || trimmed.startsWith("https://"))
    return trimmed;
  return `https://${trimmed}`;
};

const DEFAULT_API_BASE = "https://wedev-api.sky.pro";
const API_BASE = normalizeBaseUrl(
  process.env.REACT_APP_API_BASE_URL ?? DEFAULT_API_BASE,
);

/**
 * Собирает абсолютный URL API из относительного пути endpoint.
 */
export const buildApiUrl = (path: string) => `${API_BASE}${path}`;

const parseApiError = async (response: Response): Promise<string> => {
  try {
    const payload = await response.json();
    if (payload?.message) return payload.message;
  } catch {
    // ignore parse error
  }
  return `Ошибка запроса (${response.status})`;
};

/**
 * Общий HTTP-обертка для запросов с timeout и единообразной обработкой ошибок API.
 */
export async function apiRequest<TResponse>(
  url: string,
  init: RequestInit,
): Promise<TResponse> {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), 15000);
  let response: Response;
  try {
    response = await fetch(url, {
      ...init,
      headers: init.headers ?? {},
      cache: "no-store",
      signal: controller.signal,
    });
  } catch {
    throw new Error("Сервер недоступен, попробуйте позже");
  } finally {
    clearTimeout(timeout);
  }

  if (!response.ok) {
    throw new Error(await parseApiError(response));
  }

  if (response.status === 204) {
    return {} as TResponse;
  }

  return response.json() as Promise<TResponse>;
}
